VALUES
  ('elementary-7fec267e-moex-00194', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-753c7f7d', 'sub-elementary-7fec267e-04', NULL, 'single_choice', '有關公民參與的相關敘述，下列何者錯誤？', '["搭便車效應說明了公民參與的意願有可能不足", "公民參與的過程往往有利益衝突，因而需要協商或排解的制度設計", "公民參與會極大化行政效率", "公民參與有助於提高政府施政的正當性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "e27a584f884b", "answer_pdf_sha1": "d4e6060a16b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00195', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-753c7f7d', 'sub-elementary-7fec267e-04', NULL, 'single_choice', '近年來，我國部分地方政府嘗試採行參與式預算（participatorybudgeting）。有關其推動情形之敘述，下 列何者正確？', '["不一定是具有選舉投票權、且在當地設籍的公民才得參與", "各地參與式預算過程所執行的預算規模，已達該地方政府總預算八成以上", "文官為維持中立，應委託非營利組織負責推動，自己不介入、不參與", "地方制度法規定，自2025年起，地方政府須定期採行參與式預算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "e27a584f884b", "answer_pdf_sha1": "d4e6060a16b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00196', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '假定甲國的生產可能曲線往右上方擴增，下列何者可能是甲國生產可能性曲線發生變化的原因？', '["貧富差距縮小", "經濟出現停滯", "失業率上升", "生產技術進步"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00197', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '經濟制度是指政府介入人民經濟生活的方式與程度，下列有關「市場經濟制度」的敘述，何者錯誤？', '["政府保障人民的消費自由", "政府尊重市場的價格機能", "政府讓個人依自利做決策", "政府將生產工具收歸國有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00198', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '某列車與一輛從斜坡上跌落到鐵軌上的工程車相撞後出軌，造成人員傷亡慘重。事故發生後，某位脫困乘 客因被其他人拍到站在事故旁的邊坡，而被媒體誤報為「偷偷施工又見死不救的工人」，導致該名乘客被 誤解的網路鄉民肉搜與圍剿。從媒體識讀的角度檢視，何者最適合用來描述前述媒體報導所引發的現象？', '["媒體未善盡查證責任，報導內容出現不實的訊息", "媒體為搶收視率，以煽情的內容渲染大眾的情緒", "媒體形塑勞工負面刻板印象，加劇民眾對勞工的歧視", "媒體報導檢察官尚在調查的訊息，違反偵查不公開原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00199', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '政府利用租稅課徵與財政支出的手段，可以發揮一定的經濟效果，下列有關政府財政收支的敘述，何者 正確？', '["降低進口關稅可保護本國就業機會，增加消費者福利", "提高營業稅與貨物稅稅率，可縮小社會財富分配差距", "降低土地增值稅稅率，助長土地投機不利租稅公平性", "擴大公共工程的投資性支出，會增加總體經濟的供給，可刺激經濟景氣的復甦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00200', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '某報報導：「疫情升溫，清境、日月潭及溪頭等地的旅館業表示，退房率大約一至二成，且訂房也沒像往 年熱絡，價格正往下修正……」其他條件不變下，試問前述報導最符合下列何種現象？', '["需求曲線不動，需求量（quantitydemanded）減少", "需求曲線不動，需求量（quantitydemanded）增加", "需求曲線左移，需求量（quantitydemanded）減少", "需求曲線左移，需求量（quantitydemanded）增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00201', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '「現代社會公領域重視的理性、反思、對等、協商等準則也滲透到私領域，個人的主體性應受重視，我們 應強調情感關係是建立在對話基礎之上，而非威權領導、自我投射或利益交換」下列何者最可能支持前述 觀點？', '["天下無不是的父母，我們應體諒父母管教行為背後的用心", "門當戶對為基礎的婚姻才能平衡雙方的權力與價值，避免婚姻難以維持", "百善孝為先，孝順是為人基本美德，以回報父母養育之恩", "愛過不後悔，接受分手結尾，即便愛得濃烈，分手仍可能是存在的選項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00202', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '下列四種主張何者最符合多元文化主義的精神？', '["政府對弱勢族群提供資源協助其文化活動推行", "為區隔文化差異，國內各族群分別成立自治區", "將國內每種族群語言列為國民教育共同必修", "為尊重少數族群文化，應立法限制大眾媒體評論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00203', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '綠島某民宿業者捕殺保育魚類龍王鯛，引發民眾強力譴責，海洋委員會海巡署將民宿業者移送法辦。依財 貨的性質來分類，保育魚類龍王鯛屬於下列何者？', '["不具獨享性且無排他性", "具獨享性且具排他性", "不具獨享性但具排他性", "具獨享性但無排他性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
